</head>
<body>
  <h1>2048</h1>
  <div class="header">
    <div class="score-box">
      <div class="label">Score</div>
      <div id="score">0</div>
    </div>
    <button id="reset">New Game</button>
  </div>
  <div id="board"></div>
  <p class="hint">Use arrow keys to play</p>
<script>
(function () {
  const SIZE = 4;
  let grid = [];
  let currentScore = 0;

  function emptyGrid() {
    return Array.from({ length: SIZE }, () => Array(SIZE).fill(0));
  }

  function cloneGrid(g) {
    return g.map(row => row.slice());
  }

  function boardsEqual(a, b) {
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (a[r][c] !== b[r][c]) return false;
    return true;
  }

  function emptyCells() {
    const cells = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (grid[r][c] === 0) cells.push({ r, c });
    return cells;
  }

  function spawnTile() {
    const cells = emptyCells();
    if (cells.length === 0) return;
    const pick = cells[Math.floor(Math.random() * cells.length)];
    grid[pick.r][pick.c] = Math.random() < 0.9 ? 2 : 4;
  }

  function slideLine(line) {
    // Slide non-zeros to the front, merge equal neighbours once
    const tiles = line.filter(v => v !== 0);
    const result = [];
    let scoreAdd = 0;
    let i = 0;
    while (i < tiles.length) {
      if (i + 1 < tiles.length && tiles[i] === tiles[i + 1]) {
        const merged = tiles[i] * 2;
        result.push(merged);
        scoreAdd += merged;
        i += 2;
      } else {
        result.push(tiles[i]);
        i += 1;
      }
    }
    while (result.length < SIZE) result.push(0);
    return { line: result, scoreAdd };
  }

  function moveLeft() {
    let scoreAdd = 0;
    const next = emptyGrid();
    for (let r = 0; r < SIZE; r++) {
      const { line, scoreAdd: s } = slideLine(grid[r]);
      next[r] = line;
      scoreAdd += s;
    }
    return { next, scoreAdd };
  }

  function moveRight() {
    let scoreAdd = 0;
    const next = emptyGrid();
    for (let r = 0; r < SIZE; r++) {
      const reversed = grid[r].slice().reverse();
      const { line, scoreAdd: s } = slideLine(reversed);
      next[r] = line.reverse();
      scoreAdd += s;
    }
    return { next, scoreAdd };
  }

  function moveUp() {
    let scoreAdd = 0;
    const next = emptyGrid();
    for (let c = 0; c < SIZE; c++) {
      const col = [];
      for (let r = 0; r < SIZE; r++) col.push(grid[r][c]);
      const { line, scoreAdd: s } = slideLine(col);
      for (let r = 0; r < SIZE; r++) next[r][c] = line[r];
      scoreAdd += s;
    }
    return { next, scoreAdd };
  }

  function moveDown() {
    let scoreAdd = 0;
    const next = emptyGrid();
    for (let c = 0; c < SIZE; c++) {
      const col = [];
      for (let r = 0; r < SIZE; r++) col.push(grid[r][c]);
      const reversed = col.reverse();
      const { line, scoreAdd: s } = slideLine(reversed);
      const restored = line.reverse();
      for (let r = 0; r < SIZE; r++) next[r][c] = restored[r];
      scoreAdd += s;
    }
    return { next, scoreAdd };
  }

  function doMove(dir) {
    let result;
    switch (dir) {
      case 'left':  result = moveLeft();  break;
      case 'right': result = moveRight(); break;
      case 'up':    result = moveUp();    break;
      case 'down':  result = moveDown();  break;
      default: return false;
    }
    if (boardsEqual(grid, result.next)) return false;
    grid = result.next;
    currentScore += result.scoreAdd;
    spawnTile();
    render();
    return true;
  }

  function render() {
    const boardEl = document.getElementById('board');
    boardEl.innerHTML = '';
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const v = grid[r][c];
        const cell = document.createElement('div');
        cell.className = 'cell';
        cell.dataset.v = v;
        cell.textContent = v === 0 ? '' : String(v);
        boardEl.appendChild(cell);
      }
    }
    document.getElementById('score').textContent = String(currentScore);
  }

  function reset() {
    grid = emptyGrid();
    currentScore = 0;
    spawnTile();
    spawnTile();
    render();
  }

  window.game = {
    size: SIZE,
    reset: reset,
    move: function (dir) {
      return doMove(dir);
    },
    board: function () {
      return cloneGrid(grid);
    },
    setBoard: function (arr) {
      grid = arr.map(row => row.slice());
      render();
    },
    score: function () {
      return currentScore;
    }
  };

  document.getElementById('reset').addEventListener('click', reset);

  document.addEventListener('keydown', function (e) {
    const map = {
      ArrowLeft: 'left',
      ArrowRight: 'right',
      ArrowUp: 'up',
      ArrowDown: 'down'
    };
    if (map[e.key]) {
      e.preventDefault();
      doMove(map[e.key]);
    }
  });

  reset();
})();
</script>
</body>
</html>
